import React from 'react';

// ============================================================================
// Icon component variants
// ============================================================================

interface IconProps {
  className?: string;
  size?: number;
  fill?: string;
  title?: string;
}

const SvgIcon: React.FC<IconProps & { viewBox: string; path: string }> = ({
  className,
  size = 16,
  fill = 'currentColor',
  viewBox,
  path,
  title,
}) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    viewBox={viewBox}
    width={size}
    height={size}
    fill={fill}
    className={className}
    role={title ? 'img' : 'presentation'}
    aria-label={title}
    aria-hidden={!title}
  >
    {title && <title>{title}</title>}
    <path d={path} />
  </svg>
);

interface MultiPathIconProps extends IconProps {
  viewBox: string;
  paths: { d: string; fill?: string | null }[];
}

const MultiPathSvgIcon: React.FC<MultiPathIconProps> = ({
  className,
  size = 16,
  fill = 'currentColor',
  viewBox,
  paths,
  title,
}) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    viewBox={viewBox}
    width={size}
    height={size}
    fill={fill}
    className={className}
    role={title ? 'img' : 'presentation'}
    aria-label={title}
    aria-hidden={!title}
  >
    {title && <title>{title}</title>}
    {paths.map((p, i) => (
      <path key={i} d={p.d} fill={p.fill ?? fill} />
    ))}
  </svg>
);

interface PolygonIconProps extends IconProps {
  viewBox: string;
  polygons: string[];
}

const PolygonSvgIcon: React.FC<PolygonIconProps> = ({
  className,
  size = 16,
  fill = 'currentColor',
  viewBox,
  polygons,
  title,
}) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    viewBox={viewBox}
    width={size}
    height={size}
    fill={fill}
    className={className}
    role={title ? 'img' : 'presentation'}
    aria-label={title}
    aria-hidden={!title}
  >
    {title && <title>{title}</title>}
    {polygons.map((points, i) => (
      <polygon key={i} points={points} fill={fill} />
    ))}
  </svg>
);

